              pairwise_adjustments: true,
              confidence_gap_threshold: 0.1,
            },
            multi_label_selection: {
              max_labels: 3,
              min_secondary_confidence: 0.3,
              allowed_combinations: ['financial+actionable', 'newsletter+informational'],
            },
            ai_routing: {
              high_confidence_threshold: 0.8,
              ai_required_threshold: 0.5,
              skip_ai_conditions: ['has_hard_assertion', 'confidence_above_threshold'],
            },
          },
          category_signals: {
            financial: {
              hard_assertions: {
                from_domains_ref: {
                  source_group: 'financial_institutions',
                  confidence: 'high',
                },
                subject_prefixes: ['Receipt:', 'Invoice:', 'Payment'],
              },
              strong_indicators: {
                subject_contains: ['payment', 'invoice', 'receipt', 'billing'],
                body_contains: ['$', 'total:', 'amount due', 'payment method'],
              },
            },
            newsletter: {
              hard_assertions: {
                from_domains_ref: {
                  source_group: 'newsletter_senders',
                  confidence: 'high',
                },
              },
              strong_indicators: {
                subject_contains: ['newsletter', 'weekly update', 'digest'],
                body_contains: ['unsubscribe', 'mailing list', 'newsletter'],
              },
            },
          },
          confidence_thresholds: {
            high_confidence: 0.8,
            medium_confidence: 0.6,
            low_confidence: 0.4,
            ai_classification_required: 0.5,
            manual_review_required: 0.3,
            secondary_label_min_gap: 0.15,
          },
          multi_label_policy: {
            max_top_level_labels: 2,
            min_confidence_for_additional: 0.4,
            min_delta_primary_secondary: 0.1,
            allow_financial_actionable_copresence: true,
          },
          domain_signal_overrides: {
            financial: {
              hard_include: ['bank.com', 'paypal.com'],
              hard_exclude: ['spam.com'],
              strong_include: ['finance.com'],
              strong_exclude: ['marketing.com'],
            },
          },
          domain_signal_resolution: {
            mode: 'runtime_resolved',
            source: 'config/domain-sources.json',
            notes: 'Domain resolution configuration',
          },
          top_level_categories: {
            financial: {
              description: 'Financial transactions and communications',
              subtypes: {
                receipt: {
                  description: 'Purchase receipts and confirmations',
                  rule_based_classification: {
                    high_confidence: [
                      {
                        field: 'subject',
                        operation: 'contains_any',
                        values: ['receipt', 'purchase confirmation'],
                        weight: 1.0,
                      },
                    ],
                  },
                },
              },
              ai_final_classification: {
                category_description: 'Financial and monetary communications',
                decision_criteria: ['Contains monetary amounts', 'Related to payments or transactions'],
              },
            },
          },
          attributes: {
            schema: {
              urgency: {
                type: 'enum',
                values: ['low', 'medium', 'high'],
                description: 'Email urgency level',
              },
              self_sent: {
                type: 'boolean',
                description: 'Whether email was sent by the user',
              },
            },
            detectors: [
              {
                attribute: 'urgency',
                field: 'subject',
                operation: 'contains_any',
                values: ['URGENT', 'ASAP', 'IMMEDIATE'],
              },
            ],
            derived: {
              from_financial_institution: {
                logic: 'domain_lookup AND attribute_match',
                notes: 'Derived from domain source and attribute detection',
              },
            },
            attribute_bonus_map: {
              financial: {
                has_money_amount: 0.2,
                from_financial_institution: 0.3,
              },
            },
          },
          attribute_relevance: {
            _roles_legend: {
              CORE: 'Essential for category determination',
              PRIMARY_BOOST: 'Strong positive indicator',
              SECONDARY_BOOST: 'Moderate positive indicator',
              DISAMBIGUATOR: 'Helps resolve close decisions',
