              },
            },
          },
          ai_prompts: {
            feature_extraction: {
              system_prompt: ['You are an email analysis expert.'],
              user_prompt: ['Analyze this email for classification features:'],
            },
            final_classification: {
              system_prompt: ['You are an email categorization expert.'],
              user_prompt: ['Classify this email into the appropriate category:'],
            },
          },
          feature_extraction_schema: {
            type: 'object',
            properties: {
              category: { type: 'string' },
              confidence: { type: 'number' },
              features: { type: 'array' },
            },
            required: ['category', 'confidence'],
          },
        },
        schemaVersion: '1.0.0',
        validationPassed: false, // Will be set by validation
        validationErrors: [],
        compiledRules: [],
