      const response: ConfigValidationResponse = await engine.validateConfig(request);

      // Contract validation for configuration validation
      expect(response).toBeDefined();
      expect(response.isValid).toBe(true);
      expect(response.configurationHash).toBeDefined();
      expect(response.validationErrors).toHaveLength(0);
      expect(response.validationWarnings).toBeDefined();

      // Schema validation results
      expect(response.schemaValidation).toBeDefined();
      expect(response.schemaValidation.passed).toBe(true);
      expect(response.schemaValidation.errors).toHaveLength(0);

      // Rule integrity validation
      expect(response.ruleValidation).toBeDefined();
      expect(response.ruleValidation.totalRules).toBeGreaterThan(0);
      expect(response.ruleValidation.validRules).toBe(response.ruleValidation.totalRules);
      expect(response.ruleValidation.invalidRules).toHaveLength(0);

      // Attribute matrix validation
