      expect(response.attributeValidation.matrixComplete).toBe(true);
      expect(response.attributeValidation.missingMappings).toHaveLength(0);

      // Compiled rules generation
      expect(response.compiledRules).toBeDefined();
      expect(response.compiledRules.length).toBeGreaterThan(0);
      expect(response.compiledRules[0]).toMatchObject({
        category: expect.any(String),
        subtype: expect.any(String),
        tier: expect.stringMatching(/^(high|medium|low)_confidence$/),
        pattern: expect.any(Object),
        weight: expect.any(Number),
      });

      // Performance metrics
      expect(response.validationDurationMs).toBeGreaterThan(0);
      expect(response.validationDurationMs).toBeLessThan(5000);
    });

    it('should detect configuration schema violations', async () => {
      const invalidConfiguration = {
        version: '', // Invalid empty version
        processing_config: {
          // Missing required version field
          settings: {
            initialization: {
              apply_hard_assertions: 'invalid_boolean', // Invalid type
            },
          },
          confidence_thresholds: {
            high_confidence: 1.5, // Invalid - exceeds 1.0
            medium_confidence: -0.1, // Invalid - negative value
          },
        },
      } as Partial<CategoryConfiguration>;

      const request: ConfigValidationRequest = {
        configuration: invalidConfiguration,
        validateAgainstSchema: true,
      };

      // This MUST fail - no validation exists yet
      const response = await engine.validateConfig(request);

      expect(response.isValid).toBe(false);
      expect(response.validationErrors.length).toBeGreaterThan(0);
      expect(response.schemaValidation.passed).toBe(false);
      expect(response.schemaValidation.errors.length).toBeGreaterThan(0);

      // Should identify specific schema violations
      expect(
        response.schemaValidation.errors.some((error) => error.field === 'version' && error.message.includes('empty'))
      ).toBe(true);
      expect(
        response.schemaValidation.errors.some(
          (error) => error.field === 'processing_config.settings.initialization.apply_hard_assertions'
        )
      ).toBe(true);
