      const emailContent: EmailContent = {
        id: 'single-test-001',
        threadId: 'thread-single-001',
        subject: 'Receipt for your purchase - Order #INV-2024-001',
        from: {
          email: 'receipts@store.com',
          name: 'Store Receipts',
          raw: 'Store Receipts <receipts@store.com>',
        },
        to: [
          {
            email: 'customer@example.com',
            name: 'Customer',
            raw: 'Customer <customer@example.com>',
          },
        ],
        date: new Date('2025-09-28T14:30:00Z'),
        bodyPlain: `Thank you for your purchase!

Order Details:
- Order #: INV-2024-001
- Total: $129.99
- Payment Method: Credit Card ending in 4567
- Date: September 28, 2025

Items:
1. Wireless Headphones - $99.99
2. Shipping - $9.99
3. Tax - $20.01

Your order will be shipped within 2 business days.`,
        bodyHtml: `<h1>Thank you for your purchase!</h1>
<h2>Order Details:</h2>
<ul>
  <li>Order #: INV-2024-001</li>
  <li>Total: $129.99</li>
