/**
 * Contract Test: Classification Engine Single Email Endpoint
 *
 * This test MUST FAIL until implementation is complete.
 * Tests the /classify/single endpoint according to OpenAPI specification.
 */

import { ClassificationEngine } from '../../src';
import { EmailContent, SingleClassificationRequest, SingleClassificationResponse } from '../../src/types/api-types';

describe('Classification Engine - Single Email Classification API Contract', () => {
  let engine: ClassificationEngine;

  beforeEach(() => {
    // This will fail - no implementation exists yet
    engine = new ClassificationEngine();
  });

  describe('POST /classify/single', () => {
    it('should classify a single email with full explainability trace', async () => {
      const emailContent: EmailContent = {
        id: 'single-test-001',
        threadId: 'thread-single-001',
        subject: 'Receipt for your purchase - Order #INV-2024-001',
        from: {
          email: 'receipts@store.com',
          name: 'Store Receipts',
          raw: 'Store Receipts <receipts@store.com>',
        },
        to: [
          {
            email: 'customer@example.com',
            name: 'Customer',
            raw: 'Customer <customer@example.com>',
          },
        ],
        date: new Date('2025-09-28T14:30:00Z'),
        bodyPlain: `Thank you for your purchase!

Order Details:
- Order #: INV-2024-001
- Total: $129.99
- Payment Method: Credit Card ending in 4567
- Date: September 28, 2025

Items:
1. Wireless Headphones - $99.99
2. Shipping - $9.99
3. Tax - $20.01

Your order will be shipped within 2 business days.`,
        bodyHtml: `<h1>Thank you for your purchase!</h1>
<h2>Order Details:</h2>
<ul>
  <li>Order #: INV-2024-001</li>
  <li>Total: $129.99</li>
  <li>Payment Method: Credit Card ending in 4567</li>
  <li>Date: September 28, 2025</li>
</ul>
<h2>Items:</h2>
<ol>
  <li>Wireless Headphones - $99.99</li>
  <li>Shipping - $9.99</li>
  <li>Tax - $20.01</li>
</ol>
<p>Your order will be shipped within 2 business days.</p>`,
        headers: [
          { name: 'Message-ID', value: '<receipt-001@store.com>' },
          { name: 'From', value: 'Store Receipts <receipts@store.com>' },
          { name: 'Subject', value: 'Receipt for your purchase - Order #INV-2024-001' },
          { name: 'X-Priority', value: '3' },
        ],
      };

      const request: SingleClassificationRequest = {
        email: emailContent,
        sessionId: 'single-123e4567-e89b-12d3-a456-426614174000',
        includeExplainability: true,
        configVersion: 'v1.0.0-test',
      };

      // This MUST fail - no implementation exists
      const response: SingleClassificationResponse = await engine.classifySingle(request);

      // Contract validation for single email classification
      expect(response).toBeDefined();
      expect(response.sessionId).toBe(request.sessionId);
      expect(response.emailId).toBe(emailContent.id);
      expect(response.classification.primaryCategory).toBe('financial'); // Should detect as receipt
      expect(response.classification.secondaryCategories).toContain('receipt');
      expect(response.classification.confidence).toBeGreaterThanOrEqual(0.8); // High confidence for clear receipt

      // Explainability trace validation (detailed for single email)
      expect(response.explainabilityTrace).toBeDefined();

      // Hard assertions should trigger for receipt keywords
      expect(response.explainabilityTrace!.hardAssertions).toBeDefined();
      expect(response.explainabilityTrace!.hardAssertions.length).toBeGreaterThan(0);

      // Strong indicators should detect financial terms
      expect(response.explainabilityTrace!.strongIndicators).toBeDefined();
      expect(
        response.explainabilityTrace!.strongIndicators.some(
          (indicator) => indicator.category === 'financial' && indicator.seedScore > 0
        )
      ).toBe(true);

      // Rule scoring should identify receipt patterns
      expect(response.explainabilityTrace!.ruleScoring).toBeDefined();
      expect(
        response.explainabilityTrace!.ruleScoring.some((rule) => rule.category === 'financial' && rule.rawScore > 0)
      ).toBe(true);

      // Attribute detection should find money amounts and order numbers
      expect(response.explainabilityTrace!.attributeDetection).toBeDefined();
      expect(response.explainabilityTrace!.attributeDetection.length).toBeGreaterThan(0);

      // Check for detection of money amounts
      const hasMoneyAmount = response.explainabilityTrace!.attributeDetection.some((result: AttributeDetectionResult) =>
        result.detected_attributes.some((attr: DetectedAttribute) => attr.attribute_name === 'has_money_amount')
      );
      expect(hasMoneyAmount).toBe(true);

      // Check for detection of order numbers
      const hasOrderNumber = response.explainabilityTrace!.attributeDetection.some((result: AttributeDetectionResult) =>
        result.detected_attributes.some((attr: DetectedAttribute) => attr.attribute_name === 'has_order_number')
      );
      expect(hasOrderNumber).toBe(true);

      // Final decision reason should be clear
      expect(response.explainabilityTrace!.finalDecisionReason).toContain('receipt');
      expect(response.explainabilityTrace!.finalDecisionReason).toContain('financial');

      // Score breakdown validation
      expect(response.classification.scoreBreakdown).toBeDefined();
      expect(response.classification.scoreBreakdown.categoryScores.financial).toBeDefined();
      expect(response.classification.scoreBreakdown.categoryScores.financial.finalScore).toBeGreaterThan(0.8);

      // Attribute context validation
      expect(response.classification.attributeContext).toBeDefined();
      expect(response.classification.attributeContext.urgency).toBe('low'); // Receipts are not urgent
      expect(response.classification.attributeContext.domains).toContain('store.com');

      // Performance requirement
      expect(response.processingDurationMs).toBeLessThan(5000); // Single email should be faster
    });

    it('should handle emails requiring AI routing', async () => {
      const ambiguousEmail: EmailContent = {
        id: 'ambiguous-001',
        threadId: 'thread-ambiguous-001',
        subject: 'Important update regarding your account',
        from: {
          email: 'noreply@ambiguouscompany.com',
          name: 'Ambiguous Company',
          raw: 'Ambiguous Company <noreply@ambiguouscompany.com>',
        },
        to: [
          {
            email: 'user@example.com',
            name: 'User',
            raw: 'User <user@example.com>',
          },
        ],
        date: new Date('2025-09-28T11:00:00Z'),
        bodyPlain:
          'We wanted to let you know about some changes to our service. Please review the attached document for more information.',
        bodyHtml:
          '<p>We wanted to let you know about some changes to our service. Please review the attached document for more information.</p>',
        headers: [{ name: 'Message-ID', value: '<update-001@ambiguouscompany.com>' }],
      };

      const request: SingleClassificationRequest = {
        email: ambiguousEmail,
        sessionId: 'ai-routing-test-001',
        includeExplainability: true,
      };

      // This MUST fail - no implementation exists
      const response = await engine.classifySingle(request);

      // Should route to AI when rule-based classification is uncertain
      expect(response.classification.aiRoutingUsed).toBe(true);
      expect(response.explainabilityTrace!.aiRouting).toBeDefined();
      expect(response.explainabilityTrace!.aiRouting!.reason).toContain('insufficient confidence');
      expect(response.classification.confidence).toBeLessThan(0.8); // Should indicate uncertainty
    });

    it('should handle emails with multiple categories', async () => {
      const multiCategoryEmail: EmailContent = {
        id: 'multi-category-001',
        threadId: 'thread-multi-001',
        subject: 'Urgent: Payment reminder and account update required',
        from: {
          email: 'billing@financialservice.com',
          name: 'Financial Service',
          raw: 'Financial Service <billing@financialservice.com>',
        },
        to: [
          {
            email: 'user@example.com',
            name: 'User',
            raw: 'User <user@example.com>',
          },
        ],
        date: new Date('2025-09-28T16:00:00Z'),
        bodyPlain:
          'URGENT: Your payment of $250.00 is overdue. Please update your account information immediately to avoid service interruption.',
        bodyHtml:
          '<p><strong>URGENT:</strong> Your payment of $250.00 is overdue. Please update your account information immediately to avoid service interruption.</p>',
        headers: [
          { name: 'Message-ID', value: '<urgent-payment-001@financialservice.com>' },
          { name: 'X-Priority', value: '1' },
        ],
      };

      const request: SingleClassificationRequest = {
        email: multiCategoryEmail,
        sessionId: 'multi-category-test-001',
        includeExplainability: true,
      };

      // This MUST fail - no implementation exists
      const response = await engine.classifySingle(request);

      // Should detect multiple categories
      expect(response.classification.primaryCategory).toBe('financial');
      expect(response.classification.secondaryCategories).toContain('actionable');
      expect(response.classification.attributeContext.urgency).toBe('high');

      // Multi-label selection should explain the decision
      expect(response.explainabilityTrace!.multiLabelSelection).toBeDefined();
      expect(response.explainabilityTrace!.multiLabelSelection[0].selectedCategories).toContain('financial');
      expect(response.explainabilityTrace!.multiLabelSelection[0].selectedCategories).toContain('actionable');
    });

    it('should validate single email request format', async () => {
      const invalidRequest = {
        email: {
          id: '', // Invalid empty ID
          subject: undefined, // Missing required field
          from: null, // Invalid format
        },
        sessionId: 'invalid-test-001',
      } as unknown as SingleClassificationRequest;

      // This MUST fail - no validation exists yet
      await expect(engine.classifySingle(invalidRequest)).rejects.toThrow('Invalid email content');
    });

    it('should handle configuration errors gracefully', async () => {
      const validEmail: EmailContent = {
        id: 'config-error-001',
        threadId: 'thread-config-001',
        subject: 'Test email',
        from: {
          email: 'test@example.com',
          name: 'Test',
          raw: 'Test <test@example.com>',
        },
        to: [],
        date: new Date(),
        bodyPlain: 'Test content',
        headers: [],
      };

      const request: SingleClassificationRequest = {
        email: validEmail,
        sessionId: 'config-error-test-001',
        configVersion: 'invalid-config-version',
      };

      // This MUST fail - no config error handling exists yet
      await expect(engine.classifySingle(request)).rejects.toThrow('Configuration error');
    });
  });

  describe('Classification Performance Requirements', () => {
    it('should meet single email processing time requirements', async () => {
      const email: EmailContent = {
        id: 'performance-test-001',
        threadId: 'thread-perf-001',
        subject: 'Performance test email',
        from: {
          email: 'perf@example.com',
          name: 'Performance Test',
          raw: 'Performance Test <perf@example.com>',
        },
        to: [
          {
            email: 'user@example.com',
            name: 'User',
            raw: 'User <user@example.com>',
          },
        ],
        date: new Date(),
        bodyPlain: 'This is a performance test email with standard content.',
        headers: [],
      };

      const request: SingleClassificationRequest = {
        email,
        sessionId: 'performance-test-001',
        includeExplainability: true,
      };

      const startTime = Date.now();

      // This MUST fail - no implementation exists
      const response = await engine.classifySingle(request);

      const endTime = Date.now();
      const actualDuration = endTime - startTime;

      // Performance contract: single email should process in < 5 seconds
      expect(actualDuration).toBeLessThan(5000);
      expect(response.processingDurationMs).toBeLessThan(5000);
      expect(response.processingDurationMs).toBeGreaterThan(0);
    });
  });
});
